// UIManager — lives on PlayerController or as a Subsystem
UCLASS()
class UUIManager : public UObject
{
    GENERATED_BODY()
public:
    void Initialize(APlayerController* InOwner);

    UFUNCTION(BlueprintCallable)
    void ShowHUD();

    UFUNCTION(BlueprintCallable)
    void PushMenu(TSubclassOf<UUserWidget> MenuClass);

    UFUNCTION(BlueprintCallable)
    void PopMenu();

protected:
    UPROPERTY()
    APlayerController* Owner;

    UPROPERTY()
    UUserWidget* HUDWidget;

    UPROPERTY()
    TArray<UUserWidget*> MenuStack;

    void UpdateInputMode();
};

// UIManager.cpp
void UUIManager::PushMenu(TSubclassOf<UUserWidget> MenuClass)
{
    UUserWidget* Menu = CreateWidget<UUserWidget>(Owner, MenuClass);
    Menu->AddToViewport(10 + MenuStack.Num());
    MenuStack.Push(Menu);
    UpdateInputMode();
}

void UUIManager::PopMenu()
{
    if (MenuStack.Num() == 0) return;
    UUserWidget* Top = MenuStack.Pop();
    Top->RemoveFromParent();
    UpdateInputMode();
}

void UUIManager::UpdateInputMode()
{
    if (MenuStack.Num() > 0)
    {
        FInputModeUIOnly InputMode;
        InputMode.SetWidgetToFocus(MenuStack.Last()->TakeWidget());
        Owner->SetInputMode(InputMode);
        Owner->SetShowMouseCursor(true);
    }
    else
    {
        Owner->SetInputMode(FInputModeGameOnly());
        Owner->SetShowMouseCursor(false);
    }
}

// W_HealthBar — a dumb widget that just displays data
// In Blueprint: bind ProgressBar percentage to a float
// The HUD widget calls SetHealth from the HealthComponent delegate
UCLASS()
class UW_HealthBar : public UUserWidget
{
    GENERATED_BODY()
public:
    UFUNCTION(BlueprintCallable)
    void UpdateHealth(float Current, float Max)
    {
        if (HealthBar)
        {
            HealthBar->SetPercent(Max > 0.f ? Current / Max : 0.f);
        }
    }

protected:
    UPROPERTY(meta = (BindWidget))
    UProgressBar* HealthBar;
};
